--

CREATE FUNCTION public.booking_dlq_discard(p_dlq_id bigint, p_notes text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE booking_dlq
    SET status = 'discarded',
        resolved_at = NOW(),
        resolved_by = 'timeout',
        resolution_notes = COALESCE(p_notes, 'Max retries reached')
    WHERE dlq_id = p_dlq_id
      AND status = 'pending';
    
    RETURN FOUND;
END;
$$;


