--
-- Name: booking_dlq_resolve(bigint, text, text); Type: FUNCTION; Schema: public; Owner: neondb_owner
--

CREATE FUNCTION public.booking_dlq_resolve(p_dlq_id bigint, p_resolution_by text, p_resolution_notes text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE booking_dlq
    SET status = 'resolved',
        resolved_at = NOW(),
        resolved_by = p_resolution_by,
        resolution_notes = p_resolution_notes
    WHERE dlq_id = p_dlq_id
      AND status != 'resolved';
    
    RETURN FOUND;
END;
$$;


