--
-- Name: hybrid_search_rag_documents(public.vector, integer, text, integer, integer, double precision); Type: FUNCTION; Schema: public; Owner: neondb_owner
--

CREATE FUNCTION public.hybrid_search_rag_documents(p_embedding public.vector, p_provider_id integer, p_search_query text DEFAULT NULL::text, p_service_id integer DEFAULT NULL::integer, p_limit integer DEFAULT 5, p_similarity_threshold double precision DEFAULT 0.2) RETURNS TABLE(id uuid, title character varying, content text, summary text, source_type public.rag_source_type, metadata jsonb, similarity double precision, text_rank double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    d.id::uuid,
    d.title::character varying,
    d.content::text,
    d.summary::text,
    d.source_type::rag_source_type,
    d.metadata::jsonb,
    COALESCE(1 - (d.embedding <=> p_embedding), 0)::double precision AS similarity,
    (CASE 
      WHEN p_search_query IS NOT NULL THEN
        ts_rank(to_tsvector('spanish', d.title || ' ' || d.content), plainto_tsquery('spanish', p_search_query))
      ELSE 0
    END)::double precision AS text_rank
  FROM rag_documents d
  WHERE d.status = 'published'
    AND d.deleted_at IS NULL
    AND (d.expires_at IS NULL OR d.expires_at > now())
    AND d.provider_id = p_provider_id
    AND (p_service_id IS NULL OR d.service_id IS NULL OR d.service_id = p_service_id)
    AND (
      p_similarity_threshold <= 0 
      OR (d.embedding IS NOT NULL AND (1 - (d.embedding <=> p_embedding)) >= p_similarity_threshold)
    )
    AND (
      p_search_query IS NULL 
      OR to_tsvector('spanish', d.title || ' ' || d.content) @@ plainto_tsquery('spanish', p_search_query)
      OR (d.embedding IS NOT NULL AND (1 - (d.embedding <=> p_embedding)) > 0.8)
    )
  ORDER BY 
    (0.7 * COALESCE(1 - (d.embedding <=> p_embedding), 0)) + 
    (0.3 * CASE 
      WHEN p_search_query IS NOT NULL THEN
        ts_rank(to_tsvector('spanish', d.title || ' ' || d.content), plainto_tsquery('spanish', p_search_query))
      ELSE 0
    END) DESC
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION public.hybrid_search_rag_documents(p_embedding public.vector, p_provider_id integer, p_search_query text, p_service_id integer, p_limit integer, p_similarity_threshold double precision) OWNER TO neondb_owner;

--
-- Name: search_rag_documents(public.vector, integer, integer, integer, double precision); Type: FUNCTION; Schema: public; Owner: neondb_owner
--

CREATE FUNCTION public.search_rag_documents(p_embedding public.vector, p_provider_id integer, p_service_id integer DEFAULT NULL::integer, p_limit integer DEFAULT 5, p_similarity_threshold double precision DEFAULT 0.7) RETURNS TABLE(id uuid, title character varying, content text, summary text, source_type public.rag_source_type, metadata jsonb, similarity double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    d.id,
    d.title,
    d.content,
    d.summary,
    d.source_type,
    d.metadata,
    1 - (d.embedding <=> p_embedding) AS similarity
  FROM rag_documents d
  WHERE d.status = 'published'
    AND d.deleted_at IS NULL
    AND (d.expires_at IS NULL OR d.expires_at > now())
    AND d.provider_id = p_provider_id
    AND (p_service_id IS NULL OR d.service_id IS NULL OR d.service_id = p_service_id)
    AND 1 - (d.embedding <=> p_embedding) >= p_similarity_threshold
  ORDER BY d.embedding <=> p_embedding
  LIMIT p_limit;
END;
$$;


