--
-- Name: set_rag_published_at(); Type: FUNCTION; Schema: public; Owner: neondb_owner
--

CREATE FUNCTION public.set_rag_published_at() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.status = 'published' AND OLD.status != 'published' THEN
    NEW.published_at = now();
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.set_rag_published_at() OWNER TO neondb_owner;

--
-- Name: sync_rag_metadata(); Type: FUNCTION; Schema: public; Owner: neondb_owner
--

CREATE FUNCTION public.sync_rag_metadata() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.metadata ? 'provider_id' THEN
    NEW.provider_id := (NEW.metadata->>'provider_id')::integer;
  END IF;
  IF NEW.metadata ? 'service_id' THEN
    NEW.service_id := (NEW.metadata->>'service_id')::integer;
  END IF;
  IF NEW.metadata ? 'title' THEN
    NEW.title := (NEW.metadata->>'title')::varchar;
  END IF;
  IF NEW.metadata ? 'source_type' THEN
    NEW.source_type := (NEW.metadata->>'source_type')::rag_source_type;
  END IF;
  IF NEW.metadata ? 'status' THEN
    NEW.status := (NEW.metadata->>'status')::rag_document_status;
  END IF;
  IF NEW.metadata ? 'language' THEN
    NEW.language := (NEW.metadata->>'language')::varchar;
  END IF;
  IF NEW.metadata ? 'summary' THEN
    NEW.summary := (NEW.metadata->>'summary')::text;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.sync_rag_metadata() OWNER TO neondb_owner;

