--
-- Name: v_booking_dlq_ready_for_retry; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.v_booking_dlq_ready_for_retry AS
 SELECT dlq_id,
    booking_id,
    idempotency_key,
    provider_id,
    service_id,
    start_time,
    customer_id,
    chat_id,
    failure_reason,
    last_error_message,
    last_error_stack,
    original_payload,
    context_data,
    failure_count,
    status,
    next_retry_at,
    last_failed_at,
    resolved_at,
    created_at,
    first_failed_at,
    resolved_by,
    resolution_notes,
    updated_at
   FROM public.booking_dlq
  WHERE ((status = 'pending'::text) AND ((next_retry_at IS NULL) OR (next_retry_at <= now())))
  ORDER BY first_failed_at;


ALTER VIEW public.v_booking_dlq_ready_for_retry OWNER TO neondb_owner;

--
-- Name: v_booking_dlq_status; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.v_booking_dlq_status AS
 SELECT status,
    count(*) AS count,
    min(first_failed_at) AS oldest_failure,
    max(last_failed_at) AS most_recent_failure,
    avg(failure_count) AS avg_failure_count
   FROM public.booking_dlq
  GROUP BY status;


ALTER VIEW public.v_booking_dlq_status OWNER TO neondb_owner;

--
-- Name: v_rag_active_documents; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.v_rag_active_documents AS
 SELECT id,
    provider_id,
    service_id,
    title,
    summary,
    source_type,
    language,
    metadata,
    published_at
   FROM public.rag_documents
  WHERE ((status = 'published'::public.rag_document_status) AND (deleted_at IS NULL) AND ((expires_at IS NULL) OR (expires_at > now())));


ALTER VIEW public.v_rag_active_documents OWNER TO neondb_owner;

--
-- Name: v_rag_expiring_soon; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.v_rag_expiring_soon AS
 SELECT id,
    provider_id,
    title,
    source_type,
    expires_at,
    (expires_at - now()) AS days_remaining
   FROM public.rag_documents
  WHERE ((expires_at IS NOT NULL) AND (expires_at <= (now() + '30 days'::interval)) AND (expires_at > now()) AND (deleted_at IS NULL));


ALTER VIEW public.v_rag_expiring_soon OWNER TO neondb_owner;

--
-- Name: v_rag_stats; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.v_rag_stats AS
 SELECT provider_id,
    count(*) FILTER (WHERE ((status = 'published'::public.rag_document_status) AND (deleted_at IS NULL))) AS published_count,
    count(*) FILTER (WHERE (status = 'draft'::public.rag_document_status)) AS draft_count,
    count(*) FILTER (WHERE (status = 'archived'::public.rag_document_status)) AS archived_count,
    count(*) FILTER (WHERE ((expires_at IS NOT NULL) AND (expires_at > now()))) AS expiring_count,
    count(*) FILTER (WHERE (deleted_at IS NOT NULL)) AS deleted_count
   FROM public.rag_documents
  GROUP BY provider_id;


ALTER VIEW public.v_rag_stats OWNER TO neondb_owner;

--
-- Name: view_booking_dl_ready_retry; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.view_booking_dl_ready_retry AS
 SELECT dlq_id,
    booking_id,
    idempotency_key,
    provider_id,
    service_id,
    start_time,
    customer_id,
    chat_id,
    failure_reason,
    last_error_message,
    last_error_stack,
    original_payload,
    context_data,
    failure_count,
    status,
    next_retry_at,
    last_failed_at,
    resolved_at,
    created_at,
    first_failed_at,
    resolved_by,
    resolution_notes,
    updated_at,
    max_retries
   FROM public.booking_dlq
  WHERE ((status = 'pending'::text) AND (next_retry_at <= now()) AND (failure_count < max_retries));


ALTER VIEW public.view_booking_dl_ready_retry OWNER TO neondb_owner;

--
-- Name: view_daily_occupancy; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.view_daily_occupancy AS
 SELECT (start_time)::date AS date,
    provider_id,
    count(*) AS confirmed_bookings
   FROM public.bookings
  WHERE (status = 'CONFIRMED'::text)
  GROUP BY ((start_time)::date), provider_id;


ALTER VIEW public.view_daily_occupancy OWNER TO neondb_owner;

--
-- Name: view_dashboard_stats; Type: VIEW; Schema: public; Owner: neondb_owner
--

CREATE VIEW public.view_dashboard_stats AS
 SELECT p.id AS provider_id,
    p.name AS provider_name,
    s.id AS service_id,
    s.name AS service_name,
    b.status,
    count(b.id) AS total_count,
    COALESCE(sum(s.price) FILTER (WHERE (b.status = 'COMPLETED'::text)), (0)::numeric) AS revenue_completed,
    COALESCE(sum(s.price) FILTER (WHERE (b.status = 'CONFIRMED'::text)), (0)::numeric) AS revenue_projected
   FROM ((public.providers p
     CROSS JOIN public.services s)
     LEFT JOIN public.bookings b ON (((b.provider_id = p.id) AND (b.service_id = s.id))))
  GROUP BY p.id, p.name, s.id, s.name, b.status;


ALTER VIEW public.view_dashboard_stats OWNER TO neondb_owner;

